const searchData = $input.first().json;
const topicData = $('🗂️ Fetch Pending Topic').first().json;

let trendContext = '';
try {
  const results = searchData.organic_results || [];
  const top3 = results.slice(0, 3);
  if (top3.length > 0) {
    trendContext = top3.map((r, i) =>
      `${i+1}. ${r.title}: ${r.snippet}`
    ).join('\n');
  } else {
    trendContext = 'Use general knowledge about ' + topicData.topic;
  }
} catch(e) {
  trendContext = 'Use general knowledge about ' + topicData.topic;
}

return [{
  json: {
    topic: topicData.topic,
    brand_voice: topicData.brand_voice,
    platform_focus: topicData.platform_focus,
    trend_context: trendContext,
    _rowNumber: topicData._rowNumber || 2
  }
}];

const geminiResponse = $input.first().json;
let rawText = '';
try {
  rawText = geminiResponse.candidates[0].content.parts[0].text;
} catch(e) {
  throw new Error('Gemini error: ' + JSON.stringify(geminiResponse));
}

const cleaned = rawText.replace(/```json/gi,'').replace(/```/g,'').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  const linkedin = cleaned.match(/"linkedin_post"\s*:\s*"([\s\S]*?)(?:"\s*,\s*"twitter_post"|$)/);
  const twitter  = cleaned.match(/"twitter_post"\s*:\s*"([\s\S]*?)(?:"\s*,\s*"|$)/);
  const theme    = cleaned.match(/"content_theme"\s*:\s*"([\s\S]*?)"/);
  const hook     = cleaned.match(/"engagement_hook"\s*:\s*"([\s\S]*?)"/);
  const postTime = cleaned.match(/"best_post_time"\s*:\s*"([\s\S]*?)"/);
  const followup = cleaned.match(/"followup_content"\s*:\s*"([\s\S]*?)"/);
  parsed = {
    linkedin_post:   linkedin ? linkedin[1] : rawText.substring(0,1000),
    twitter_post:    twitter  ? twitter[1]  : '',
    content_theme:   theme    ? theme[1]    : '',
    engagement_hook: hook     ? hook[1]     : '',
    best_post_time:  postTime ? postTime[1] : '9AM',
    followup_content:followup ? followup[1] : ''
  };
}

const topicData = $('🗂️ Fetch Pending Topic').first().json;
const trendData = $('⚙️ Extract Trend Data').first().json;
const rowNum = topicData._rowNumber || topicData.rowNumber || topicData.row_number || 2;

return [{
  json: {
    linkedin_post:    parsed.linkedin_post    || '',
    twitter_post:     parsed.twitter_post     || '',
    content_theme:    parsed.content_theme    || '',
    engagement_hook:  parsed.engagement_hook  || '',
    best_post_time:   parsed.best_post_time   || '',
    followup_content: parsed.followup_content || '',
    trend_context:    trendData.trend_context || '',
    original_topic:   topicData.topic,
    brand_voice:      topicData.brand_voice,
    row_number:       rowNum,
    generated_at:     new Date().toISOString()
  }
}];

const topicData = $('🗂️ Fetch Pending Topic').first().json;
const parsedData = $('⚙️ Parse Gemini Response').first().json;

return [{
  json: {
    ...parsedData,
    row_to_update: topicData._rowNumber || 2,
    new_status: 'posted'
  }
}];

